let _pushService: WebPushService | null = null;

export function getPushService(): WebPushService {
	if (!_pushService) {
		const publicKey = process.env.VAPID_PUBLIC_KEY;
		const privateKey = process.env.VAPID_PRIVATE_KEY;
		const email = process.env.VAPID_EMAIL ?? 'admin@halo.local';

		let vapidKeys: { publicKey: string; privateKey: string };

		if (publicKey && privateKey) {
			vapidKeys = { publicKey, privateKey };
		} else {
			// Generate ephemeral keys for development
			vapidKeys = generateVapidKeys();
			console.warn(
				'[push] No VAPID_PUBLIC_KEY/VAPID_PRIVATE_KEY env vars set. ' +
					'Generated ephemeral VAPID keys — push subscriptions will break on restart.'
			);
			console.warn('[push] Public key (set as VAPID_PUBLIC_KEY):', vapidKeys.publicKey);
		}

		_pushService = new WebPushService(getDb(), { ...vapidKeys, email });
	}
	return _pushService;
}

export function getVapidPublicKey(): string {
	return getPushService()['vapid'].publicKey;
}

